2102 bool LoopVectorizationLegality::canFoldTailByMasking() const {
2103   // The only loops we can vectorize without a scalar epilogue, are loops with
2104   // a bottom-test and a single exiting block. We'd have to handle the fact
2105   // that not every instruction executes on the last iteration.  This will
2106   // require a lane mask which varies through the vector loop body.  (TODO)
2107   if (TheLoop->getExitingBlock() != TheLoop->getLoopLatch()) {
2108     LLVM_DEBUG(
2109         dbgs()
2110         << "LV: Cannot fold tail by masking. Requires a singe latch exit\n");
2111     return false;
2112   }
2113 
2114   LLVM_DEBUG(dbgs() << "LV: checking if tail can be folded by masking.\n");
2115 
2116   SmallPtrSet<const Value *, 8> ReductionLiveOuts;
2117 
2118   for (const auto &Reduction : getReductionVars())
2119     ReductionLiveOuts.insert(Reduction.second.getLoopExitInstr());
2120 
2121   // The list of pointers that we can safely read and write to remains empty.
2122   SmallPtrSet<Value *, 8> SafePointers;
2123 
2124   // Check all blocks for predication, including those that ordinarily do not
2125   // need predication such as the header block.
2126   SmallPtrSet<const Instruction *, 8> TmpMaskedOp;
2127   for (BasicBlock *BB : TheLoop->blocks()) {
2128     if (!blockCanBePredicated(BB, SafePointers, TmpMaskedOp)) {
2129       LLVM_DEBUG(dbgs() << "LV: Cannot fold tail by masking.\n");
2130       return false;
2131     }
2132   }
2133 
2134   LLVM_DEBUG(dbgs() << "LV: can fold tail by masking.\n");
2135 
